import time
import pytest
from <helper_fn> import patient_token, api_client, ensure_active_consent, cleanup_consent

@pytest.fixture()
def client():
    return api_client(base_url="<FHIR_BASE_URL>")

def test_data_access_denied_after_revoke_within_sla(client):
    token = patient_token(patient_id="pt-neg-001")
    headers = {"Authorization": f"Bearer {token}"}
    consent_id = ensure_active_consent(client, headers, patient_id="pt-neg-001")

    revoke = {"resourceType": "Consent", "id": consent_id, "status": "inactive"}
    rev_resp = client.put(f"/Consent/{consent_id}", json=revoke, headers=headers)
    assert rev_resp.status_code == 200

    # Immediate access – must be denied within SLA
    access_resp = client.get("/Patient/pt-neg-001/$everything", headers=headers)
    assert access_resp.status_code in (401, 403), (
        f"Expected 401/403 immediately after revoke, got {access_resp.status_code}"
    )

    # Access at 14 min 55 s – still within SLA
    time.sleep(895)
    access_resp2 = client.get("/Patient/pt-neg-001/$everything", headers=headers)
    assert access_resp2.status_code in (401, 403), (
        f"Expected denial within SLA window, got {access_resp2.status_code}"
    )

    cleanup_consent(client, headers, consent_id)

import pytest
from <helper_fn> import patient_token, api_client, build_consent_payload, cleanup_consent

@pytest.fixture()
def client():
    return api_client(base_url="<FHIR_BASE_URL>")

@pytest.mark.parametrize("dt,duration,expect_status", [
    ("1970-01-01T00:00:00Z", 1,    201),
    ("9999-12-31T23:59:59Z", 1,    (201, 422)),
    ("2024-01-01T00:00:00Z", 0,    422),
    ("2024-01-01T00:00:00Z", -1,   422),
])
def test_consent_boundary_timestamps_and_zero_duration(
    client, dt, duration, expect_status
):
    token = patient_token(patient_id="pt-bva-001")
    headers = {"Authorization": f"Bearer {token}"}

    payload = build_consent_payload(
        patient_id="pt-bva-001",
        status="active",
        category="research",
        date_time=dt,
        period_duration_days=duration
    )
    resp = client.post("/Consent", json=payload, headers=headers)

    if isinstance(expect_status, tuple):
        assert resp.status_code in expect_status, f"Got {resp.status_code}"
    else:
        assert resp.status_code == expect_status, f"Got {resp.status_code}"

    if resp.status_code == 422:
        body = resp.json()
        assert body.get("resourceType") == "OperationOutcome"
    elif resp.status_code == 201:
        cleanup_consent(client, headers, resp.json()["id"])

import pytest
from <helper_fn> import patient_token, practitioner_token, api_client, build_consent_payload, cleanup_consent

@pytest.fixture()
def client():
    return api_client(base_url="<FHIR_BASE_URL>")

@pytest.mark.parametrize("status,category,actor,expected_code", [
    ("entered-in-error", "research",    "patient",      422),
    ("active",           "INVALID-CAT", "patient",      422),
    ("active",           "research",    "practitioner", 403),
    ("active",           "research",    "patient",      201),
])
def test_consent_decision_table_status_category_actor(
    client, status, category, actor, expected_code
):
    if actor == "patient":
        token = patient_token(patient_id="pt-dt-001")
    else:
        token = practitioner_token(practitioner_id="prac-dt-001")
    headers = {"Authorization": f"Bearer {token}"}

    payload = build_consent_payload(
        patient_id="pt-dt-001", status=status, category=category
    )
    resp = client.post("/Consent", json=payload, headers=headers)
    assert resp.status_code == expected_code, (
        f"status={status} category={category} actor={actor}: "
        f"expected {expected_code}, got {resp.status_code}"
    )
    if resp.status_code == 201:
        cleanup_consent(client, headers, resp.json()["id"])
